class ModelNew(nn.Module):
    """
    Optimized model with fused Conv3D + Min + Softmax operation using custom CUDA kernel.
    """
    def __init__(self, in_channels, out_channels, kernel_size, dim, padding=0):
        super(ModelNew, self).__init__()
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size
        self.dim = dim
        self.padding = padding

        # Initialize weights and bias like nn.Conv3d
        self.weight = nn.Parameter(torch.empty(
            out_channels, in_channels, kernel_size, kernel_size, kernel_size
        ))
        self.bias = nn.Parameter(torch.empty(out_channels))

        # Initialize parameters
        self.reset_parameters()

        # Register the custom CUDA operation
        self.fused_op = fused_conv_min_softmax

    def reset_parameters(self):
        # Use the same initialization as nn.Conv3d
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in)
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_channels, D, H, W)
        Returns:
            torch.Tensor: Output tensor of shape (batch_size, out_channels, H, W)
        """
        # Use fused custom CUDA kernel for Conv3D + Min + Softmax
        return self.fused_op.fused_conv_min_softmax_cuda(
            x,
            self.weight,
            self.bias,
            self.kernel_size,
            self.dim,
            self.padding
        )

