                        conv_val += static_cast<float>(input[input_idx]) * 
                                   static_cast<float>(weight[weight_idx]);
                    }
                }
            }
        }
    }

    // Add bias
    conv_val += static_cast<float>(bias[oc]);

    // Store intermediate result
    const int output_idx = ((b * out_channels + oc) * out_D * out_H * out_W) + 
                          (od * out_H * out_W) + (oh * out_W) + ow;
    output[output_idx] = static_cast<scalar_t>(conv_val);
}

template<typename scalar_t>
__global__ void min_reduction_kernel(
    const scalar_t* conv_output,
    scalar_t* min_output,
    const int batch_size,
    const int out_channels,
    const int out_D, const int out_H, const int out_W,
    const int min_dim
) {
    // Each thread handles one spatial position (H, W) for each batch and channel
    const int b = blockIdx.z;  // batch
    const int oc = blockIdx.y; // output channel
    const int h = blockIdx.x;  // height
    const int w = threadIdx.x; // width

    if (w >= out_W) return;

    // Find minimum along the specified dimension (min_dim)
    float min_val = 1e10f;
    for (int d = 0; d < out_D; d++) {
        // Calculate index based on which dimension we're reducing
        int idx;
        if (min_dim == 2) {  // depth dimension
            idx = ((b * out_channels + oc) * out_D * out_H * out_W) +
                  (d * out_H * out_W) + (h * out_W) + w;
        } else if (min_dim == 3) {  // height dimension
            idx = ((b * out_channels + oc) * out_D * out_H * out_W) +
                  (h * out_D * out_W) + (d * out_W) + w;
        } else {  // width dimension (min_dim == 4)
            idx = ((b * out_channels + oc) * out_D * out_H * out_W) +
                  (w * out_D * out_H) + (d * out_H) + h;
        }

        float val = static_cast<float>(conv_output[idx]);
        min_val = fminf(min_val, val);
    }

    // Store min value
    const int output_idx = ((b * out_channels + oc) * out_H * out_W) + (h * out_W) + w;
    min_output[output_idx] = static_cast<scalar_t>(min_val);
}

template<typename scalar_t>
__global__ void softmax_kernel(
    scalar_t* output,
    const int batch_size,
    const int out_channels,
    const int out_H,
    const int out_W
) {
    const int b = blockIdx.x;  // batch
    const int h = blockIdx.y;  // height
    const int w = threadIdx.x; // width

    if (w >= out_W) return;

    // First pass: find max value for softmax stability
    float max_val = -INFINITY;
    for (int oc = 0; oc < out_channels; oc++) {
        const int idx = ((b * out_channels + oc) * out_H * out_W) + (h * out_W) + w;
        float val = static_cast<float>(output[idx]);
        max_val = fmaxf(max_val, val);
    }

    // Second pass: compute exponentials and sum
    float sum_val = 0.0f;
    for (int oc = 0; oc < out_channels; oc++) {
        const int idx = ((b * out_channels + oc) * out_H * out_W) + (h * out_W) + w;
        float val = static_cast<float>(output[idx]);
        float exp_val = expf(val - max_val);
        output[idx] = static_cast<scalar_t>(exp_val);
        sum_val += exp_val;
    }

    // Third pass: normalize
    for (int oc = 0; oc < out_channels; oc++) {
        const int idx = ((b * out_channels + oc) * out_H * out_W) + (h * out_W) + w;
        float val = static_cast<float>(output[idx]);
        output[idx] = static_cast<scalar_t>(val / sum_val);
    }
}

torch::Tensor fused_conv_min_softmax_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    int kernel_size,
    int min_dim,
    int pad
) {
    // Get tensor dimensions
    const int batch_size = input.size(0);
    const int in_channels = input.size(1);
    const int D = input.size(2);
    const int H = input.size(3);
    const int W = input.size(4);
    const int out_channels = weight.size(0);

    // Calculate output dimensions
    const int out_D = D - kernel_size + 1 + 2 * pad;
    const int out_H = H - kernel_size + 1 + 2 * pad;
    const int out_W = W - kernel_size + 1 + 2 * pad;

    // Create intermediate tensor for convolution output
    auto conv_output = torch::zeros({batch_size, out_channels, out_D, out_H, out_W}, 
                                   torch::TensorOptions().device(input.device()).dtype(input.dtype()));

    // Create final output tensor (after min reduction)
    auto min_output = torch::zeros({batch_size, out_channels, out_H, out_W}, 
                                  torch::TensorOptions().device(input.device()).dtype(input.dtype()));

    // Configure kernel launch for conv
    dim3 grid_conv(out_D, out_channels, batch_size);
    dim3 block_conv(min(32, out_W), min(32, out_H));

    // Launch conv kernel
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_conv", [&] {
        fused_conv_min_softmax_kernel<scalar_t><<<grid_conv, block_conv>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.data_ptr<scalar_t>(),
            conv_output.data_ptr<scalar_t>(),
            batch_size,
            in_channels,
            out_channels,
            D, H, W,
            kernel_size,
            min_dim,
            pad
        );
    });

    // Configure kernel launch for min reduction
    dim3 grid_min(out_H, out_channels, batch_size);
    const int block_size_min = min(1024, out_W);

    // Launch min reduction kernel
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "min_reduction", [&] {
        min_reduction_kernel<scalar_t><<<grid_min, block_size_min>>>(
            conv_output.data_ptr<scalar_t>(),
            min_output.data_ptr<scalar_t>(),
            batch_size,
            out_channels,
            out_D, out_H, out_W,
            min_dim
        );
    });

    // Configure kernel launch for softmax
    dim3 grid_softmax(batch_size, out_H);
    const int block_size_softmax = min(1024, out_W);

    // Launch softmax kernel
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "softmax", [&] {
        softmax_kernel<scalar_t><<<grid_softmax, block_size_softmax>>>(
            min_output.data_ptr<scalar_t>(),
            batch_size,
            out_channels,
            out_H,
            out_W
        );
    });

    cudaDeviceSynchronize();
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        printf("CUDA error: %s\\n", cudaGetErrorString(err));
    }

    return min_output;
}
